import axios from "axios";
import { useState } from "react";

import BudgetCard from "./BudgetCard";
import Recommendations from "./Recommendations";
import SafetyCard from "./SafetyCard";
import Itinerary from "./Itinerary";
import MapView from "./MapView";

import "./ChatBox.css";

function ChatBox() {

  const [message, setMessage] = useState("");
  const [persons, setPersons] = useState(1);

  const [response, setResponse] = useState(null);

  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {

    if (!message) {

      alert("Please enter destination");

      return;
    }

    setLoading(true);

    try {

      const res = await axios.post(
        "http://127.0.0.1:8000/chat",
        {
          message: message,
          persons: persons
        }
      );

      setResponse(res.data);

    } catch (error) {

      console.log(error);

      alert("Backend connection error");

    }

    setLoading(false);
  };

  return (

    <div className="chat-container">

      <div className="hero-section">

        <h1>🇮🇳 India AI Travel Planner</h1>

        <p>
          Plan your budget-friendly India trip with AI recommendations,
          safety analysis, itinerary planning and live map view.
        </p>

      </div>

      <div className="search-box">

        <input
          type="text"
          placeholder="Example: Goa trip, Ooty travel, Kerala tourism"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          className="input-box"
        />

        <input
          type="number"
          min="1"
          placeholder="Persons"
          value={persons}
          onChange={(e) => setPersons(e.target.value)}
          className="person-box"
        />

        <button
          onClick={sendMessage}
          className="send-btn"
        >
          Plan Trip
        </button>

      </div>

      {loading && (

        <div className="loading-box">

          <h2>Generating AI Travel Plan...</h2>

        </div>
      )}

      {response && (

        <div className="results-section">

          <div className="card ai-card">

            <h2>🤖 AI Response</h2>

            <p>{response.ai_response}</p>

          </div>

          <BudgetCard budget={response.budget} />

          <Recommendations places={response.recommendations} />

          <SafetyCard safety={response.safety} />

          <Itinerary itinerary={response.itinerary} />

          <MapView places={response.recommendations} />

        </div>
      )}

    </div>
  );
}

export default ChatBox;
